UPDATE menu_items
SET image_url = CASE id
  WHEN '14000000-0000-0000-0000-000000000001' THEN 'https://images.unsplash.com/photo-1568901346375-23c9450c58cd?auto=format&fit=crop&w=900&q=80'
  WHEN '14000000-0000-0000-0000-000000000002' THEN 'https://images.unsplash.com/photo-1573080496219-bb080dd4f877?auto=format&fit=crop&w=900&q=80'
  WHEN '14000000-0000-0000-0000-000000000003' THEN 'https://images.unsplash.com/photo-1544145945-f90425340c7e?auto=format&fit=crop&w=900&q=80'
  ELSE image_url
END
WHERE image_url IS NULL OR image_url = '';

UPDATE restaurants
SET status = 'approved', is_active = true
WHERE is_active = true AND status IN ('draft','pending_review');

-- AUTO-GENERATED EXPANDED RESTAURANT SEED DATA


-- Promotions / deals for storefront and customer discover
SELECT 'Weekend Feast', 'Up to 20% off selected family meals and combos this weekend.', 'https://images.unsplash.com/photo-1513104890138-7c749659a591?auto=format&fit=crop&w=1200&q=80', 6, true, now() - interval '2 days', now() + interval '30 days', '00000000-0000-0000-0000-000000000001'
WHERE NOT EXISTS (SELECT 1 FROM promotions WHERE title = 'Weekend Feast');

SELECT 'Burger Night', 'Buy one burger combo and get fries or wings at a promo price.', 'https://images.unsplash.com/photo-1568901346375-23c9450c58cd?auto=format&fit=crop&w=1200&q=80', 5, true, now() - interval '1 day', now() + interval '21 days', '00000000-0000-0000-0000-000000000001'
WHERE NOT EXISTS (SELECT 1 FROM promotions WHERE title = 'Burger Night');

SELECT 'Healthy Bowl Special', 'Fresh bowls, smoothies, and wraps on a weekday special.', 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&w=1200&q=80', 4, true, now() - interval '1 day', now() + interval '21 days', '00000000-0000-0000-0000-000000000001'
WHERE NOT EXISTS (SELECT 1 FROM promotions WHERE title = 'Healthy Bowl Special');

UPDATE featured_restaurants fr
SET promotion_id = p.id
FROM promotions p, restaurants r
WHERE fr.restaurant_id = r.id
  AND (
    (r.display_name = 'Pizza District' AND p.title = 'Weekend Feast') OR
    (r.display_name = 'Burger Boulevard' AND p.title = 'Burger Night') OR
    (r.display_name = 'Green Bowl Kitchen' AND p.title = 'Healthy Bowl Special')
  );

SELECT 'WELCOME10', 'Welcome 10%', 'Save 10% on your first order.', 'percent', 10.00, 80.00, 60.00, 1, now() - interval '2 days', now() + interval '45 days', 'platform', true, '00000000-0000-0000-0000-000000000001'
WHERE NOT EXISTS (SELECT 1 FROM coupons WHERE code = 'WELCOME10');

SELECT 'FREEDEL', 'Free Delivery', 'Enjoy free delivery on qualifying orders.', 'free_delivery', 0.00, 120.00, NULL, 2, now() - interval '2 days', now() + interval '45 days', 'platform', true, '00000000-0000-0000-0000-000000000001'
WHERE NOT EXISTS (SELECT 1 FROM coupons WHERE code = 'FREEDEL');

