SELECT 'PIZZA20', 'Pizza District Special', 'Take 20% off selected pizza orders.', 'percent', 20.00, 140.00, 90.00, 3, now() - interval '2 days', now() + interval '45 days', 'restaurant', true, '00000000-0000-0000-0000-000000000001'
