SELECT c.id, r.id
FROM coupons c
JOIN restaurants r ON r.display_name = 'Pizza District'
WHERE c.code = 'PIZZA20'
  AND NOT EXISTS (SELECT 1 FROM coupon_restaurants cr WHERE cr.coupon_id = c.id AND cr.restaurant_id = r.id);

SELECT c.id, r.id
FROM coupons c
JOIN restaurants r ON r.display_name = 'Burger Boulevard'
WHERE c.code = 'BURGER25'
  AND NOT EXISTS (SELECT 1 FROM coupon_restaurants cr WHERE cr.coupon_id = c.id AND cr.restaurant_id = r.id);

SELECT c.id, r.id
